def countAndSay(n: int) -> str:
    def generate_next(s: str) -> str:
        result = []
        count = 1
        for i in range(1, len(s)):
            if s[i] == s[i - 1]:
                count += 1
            else:
                result.append(str(count) + s[i - 1])
                count = 1
        result.append(str(count) + s[-1])
        return "".join(result)

    current = "1"
    for _ in range(n - 1):
        current = generate_next(current)
    return current
